+}): { api?: string; baseUrl?: string } | undefined {
+  const providers = params.config?.models?.providers;
+  if (!providers) {
+    return undefined;
+  }
+  for (const [providerId, entry] of Object.entries(providers)) {
+    if (normalizeLowercaseStringOrEmpty(providerId) !== params.provider) {
